render(() => {
    const [inputProps, setInputProps] = React.useState({});

    return (
        <div>
            <div style={{ width: 320 }}>
                <Input
                    block={true}
                    placeholder='Placeholder'
                    label='Label'
                    labelView={isMobile() ? 'outer' : 'inner'}
                    size={isMobile() ? 48 : 56}
                    breakpoint={BREAKPOINT}
                    {...inputProps}
                />
            </div>
            <Gap size={24} />

            <Space direction='horizontal' wrap={true}>
                <Button size={32} view='secondary' onClick={() => setInputProps({})}>
                    По умолчанию
                </Button>
                <Button
                    size={32}
                    view='secondary'
                    onClick={() => setInputProps({ disabled: true })}
                >
                    Заблокирован
                </Button>
                <Button
                    size={32}
                    view='secondary'
                    onClick={() => setInputProps({ readOnly: true })}
                >
                    Только чтение
                </Button>
            </Space>
        </div>
    );
});

render(() => {
    const [open, setOpen] = React.useState(false);

    /* Указать для IconButton через className */
    const css = `
        button[data-test-id='icon'] {
            margin-right: var(--gap-12-neg);
        }
    `;

    return (
        <div style={{ width: 320 }}>
            <style>{css}</style>
            <Input
                block={true}
                label={!isMobile() && 'Инпут с плейсхолдером'}
                placeholder={isMobile() ? 'Инпут с плейсхолдером' : 'Placeholder'}
                size={isMobile() ? 48 : 56}
                breakpoint={BREAKPOINT}
                hint='Подсказка под полем'
                rightAddons={
                    <Tooltip
                        open={open}
                        targetClassName='target'
                        content={
                            <span style={{ whiteSpace: 'pre-wrap' }}>
                                {`Сообщение тултипа\nотображается при\n${
                                    isMobile() ? 'клике' : 'наведении'
                                }`}
                            </span>
                        }
                        onOpen={() => setOpen(true)}
                        onClose={() => setOpen(false)}
                        position='right'
                    >
                        <div style={{ width: 24, height: 24, display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
                            <StatusBadge size={20} view='neutral-information' />
                        </div>
                    </Tooltip>
                }
            />
        </div>
    );
});

render(() => {
    const [success, setSuccess] = React.useState(false);
    const [value, setValue] = React.useState('');

    const handleChange = (e) => {
        const value = e.target.value;
        setValue(value);

        if (value.length === 5) {
            setSuccess(true);
        } else {
            setSuccess(false);
        }
    };

    const hasError = value.length > 5;

    return (
        <div style={{ width: 320 }}>
            <Input
                value={value}
                block={true}
                onChange={handleChange}
                label='Введите 5 символов'
                placeholder='Placeholder'
                labelView={isMobile() ? 'outer' : 'inner'}
                size={isMobile() ? 48 : 56}
                breakpoint={BREAKPOINT}
                success={success}
                error={hasError}
            />
        </div>
    );
});

render(() => {
    const [value, setValue] = React.useState('Value');

    return (
        <div style={{ width: 320 }}>
            <Input
                value={value}
                block={true}
                onChange={(e) => setValue(e.target.value)}
                label='Label'
                placeholder='Placeholder'
                labelView={isMobile() ? 'outer' : 'inner'}
                size={isMobile() ? 48 : 56}
                breakpoint={BREAKPOINT}
                clear={true}
                onClear={() => setValue('')}
            />
        </div>
    );
});

render(() => {
    const [isVisible, setIsVisible] = React.useState(false);
    const [title, setTitle] = React.useState('');
    const [valueOne, setValueOne] = React.useState('Value');
    const [valueTwo, setValueTwo] = React.useState('Value');

    const toggleVisiblity = () => setIsVisible((prev) => !prev);

    const singleIcon = () => {
        setTitle('Вы восхитительны!');
        toggleVisiblity();
    };

    const leftIcon = () => {
        setTitle('Левая');
        toggleVisiblity();
    };

    const rightIcon = () => {
        setTitle('Правая');
        toggleVisiblity();
    };

    const hideNotification = React.useCallback(() => setIsVisible(false), []);

    const styleWrapperIcons = {
        height: '100%',
        display: 'flex',
        gap: 4,
        marginRight: 'var(--gap-8-neg)',
    };

    /* Указать для IconButton через className */
    const css = `
        button[data-test-id='icon'] {
            margin-right: var(--gap-12-neg);
        }
    `;

    return (
        <div style={{ width: 320 }}>
            <style>{css}</style>
            <Input
                value={valueOne}
                block={true}
                onChange={(e) => setValueOne(e.target.value)}
                label='Label'
                placeholder='Placeholder'
                labelView={isMobile() ? 'outer' : 'inner'}
                size={isMobile() ? 48 : 56}
                breakpoint={BREAKPOINT}
                rightAddons={
                    <IconButton
                        view='secondary'
                        onClick={singleIcon}
                        icon={DiamondsMIcon}
                        size={48}
                        dataTestId='icon'
                    />
                }
            />
            <Gap size={20} />
            <Input
                value={valueTwo}
                block={true}
                onChange={(e) => setValueTwo(e.target.value)}
                label='Label'
                placeholder='Placeholder'
                labelView={isMobile() ? 'outer' : 'inner'}
                size={isMobile() ? 48 : 56}
                breakpoint={BREAKPOINT}
                rightAddons={
                    <div style={styleWrapperIcons}>
                        <IconButton
                            view='secondary'
                            onClick={leftIcon}
                            icon={DiamondsMIcon}
                            size={32}
                            alignIcon='right'
                        />
                        <IconButton
                            view='secondary'
                            onClick={rightIcon}
                            icon={FlowerMIcon}
                            size={32}
                            alignIcon='left'
                        />
                    </div>
                }
            />
            <Toast
                title={title}
                open={isVisible}
                onClose={hideNotification}
                hasCloser={false}
                autoCloseDelay={2000}
                style={{ left: isMobile() ? '30%' : '41%' }}
            />
        </div>
    );
});
